App [ width = 400, height = 140, fill = #1E3A49, textColor = whitesmoke,

    count: number = 0,                               // reactive state

    add: View [ x = 20, y = 20, width = 108, height = 34, cornerRadius = 8, fill = #2E6BE6,
        onClick() { classroot.count = classroot.count + 1 },
        Text [ x = 16, y = 8, text = "Add one" ],
        ],

    Text [ y = 74, x = { (parent.width - this.width) / 2 },
        text = { `Clicked ${count} times` },         // re-runs whenever count changes
        ],
    ]

App [ fill = white, textColor = #1A1A1E,
    fontFamily = ["system-ui", "sans-serif"], fontSize = 15,
    ]

class Panel extends View [ width = 200, height = 60, fill = whitesmoke,
    Text [ x = 12, y = 20, text = { app.dark ? "night" : "day" } ],
    ]

App [ Panel [ x = 20, y = 20 ],
    ]

App [ width = 300, height = 160, fill = white,
    card: View [ x = 20, y = 40, width = 120, height = 80, cornerRadius = 10, fill = 0x4C8DFF,
        downX: number = 0,
        startX: number = 0,
        dragging: boolean = false,
        onMouseDown(e) { downX = e.x; startX = this.x; dragging = false },
        onMouseMove(e) {
            if (Math.abs(e.x - downX) > 4) { dragging = true }
            if (dragging) { x = startX + (e.x - downX) }
            },
        onMouseUp() { dragging = false },
        ],
    ]

App [ width = 240, height = 100, fill = white, textColor = black,
    n: number = 0,
    onKeyUp(e) <- Keys {
        if (e.key == "ArrowUp") { n = n + 1 }
        else if (e.key == "ArrowDown") { n = n - 1 }
        },
    Text [ x = 20, y = 34, fontSize = 28, text = { `n = ${n}` } ],
